const StoryTitleWithCounts = ({ restaurantId, className }: { restaurantId?: string; className?: string }) => {
  const { t } = useTranslation();
  const { counts } = useStoryReactions(restaurantId);
  return (
    <span className={`flex items-center gap-2 ${className || ''}`}>
      <span className="text-xl">🏛️</span>
      {t("buildingStory.title", "Story")}
      {(counts.likes > 0 || counts.dislikes > 0) && (
        <span className="flex items-center gap-1.5 text-xs opacity-80">
          {counts.likes > 0 && <span className="flex items-center gap-0.5"><ThumbsUp className="w-3 h-3" />{counts.likes}</span>}
          {counts.dislikes > 0 && <span className="flex items-center gap-0.5"><ThumbsDown className="w-3 h-3" />{counts.dislikes}</span>}
        </span>
      )}
    </span>
  );
};

const StoryDialogContent = ({ restaurant }: { restaurant: any }) => {
  const { i18n, t } = useTranslation();
  const { user } = useAuth();
  const { buildingNarrative, iChingFull } = getBuildingStoryParts({
    photo_story_zh: restaurant?.photo_story_zh,
    photo_story_en: restaurant?.photo_story_en,
    photo_story_pt: restaurant?.photo_story_pt,
    address: restaurant?.address,
  }, i18n.language);
  // Auto-translate narrative to UI language
  const { translatedNarrative, isAutoTranslating } = useAutoTranslateNarrative(buildingNarrative || null, i18n.language);
  const { counts, userReaction, toggleReaction } = useStoryReactions(restaurant?.id);
  const [showComments, setShowComments] = useState(false);
  const { data: storyComments } = useComments(restaurant?.id || "", "story", { enabled: !!restaurant?.id });
  const commentsCount = storyComments?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  const handleShare = async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: restaurant?.name || t("buildingStory.title", "Story"), url: window.location.href });
      } else {
        await navigator.clipboard.writeText(window.location.href);
        toast.success(t("common.linkCopied", "链接已复制"));
      }
    } catch { /* cancelled */ }
  };
  
  return (
    <div className="px-6 py-5 space-y-4">
      {buildingNarrative && (
        <>
          {isAutoTranslating && !translatedNarrative && (
            <div className="flex items-center gap-2 mb-3 text-sm text-muted-foreground">
              <Loader2 className="h-4 w-4 animate-spin" />
              <span>{t("translate.translating", "翻译中...")}</span>
            </div>
          )}
          <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/90">
            {translatedNarrative || buildingNarrative}
          </p>
        </>
      )}
      {iChingFull && (
        <div className="border-l-2 border-primary/30 pl-4 py-2 bg-secondary/50 rounded-r-md mt-4">
          <IChingSection text={iChingFull} />
        </div>
      )}
      {/* Like / Dislike / Share */}
      <div className="flex items-center justify-center gap-4 pt-2 border-t border-border/50">
        <button
          onClick={() => toggleReaction.mutate({ type: "like" })}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
          }`}
        >
          <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
          {counts.likes > 0 && <span>{counts.likes}</span>}
        </button>
        <button
          onClick={() => toggleReaction.mutate({ type: "dislike" })}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
          }`}
        >
          <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
          {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
        </button>
        <button
          onClick={handleShare}
          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95"
        >
          <Share2 className="w-4 h-4" />
        </button>
        <button
          onClick={() => setShowComments(!showComments)}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
          }`}
        >
          <MessageSquare className="w-4 h-4" />
          {commentsCount > 0 && <span>{commentsCount}</span>}
        </button>
      </div>
      {/* Story Comments */}
      {showComments && restaurant?.id && (
        <div className="mt-4 pt-4 border-t border-border/50">
          <RestaurantComments targetId={restaurant.id} targetType="story" />
        </div>
      )}
    </div>
  );
};

const RestaurantTags = ({
  restaurant,
  language
}: {
  restaurant: any;
  language: string;
}) => {
  const [visibleCount, setVisibleCount] = useState(999);
  const containerRef = useRef<HTMLDivElement>(null);
  const typeTags = restaurant.type.map((type: string, idx: number) => ({
    key: `type-${idx}`,
    label: getTypeDisplayLabel(type, language),
    variant: "secondary" as const,
    color: undefined
  }));
  const allTags = typeTags;
  useEffect(() => {
    const checkOverflow = () => {
      if (!containerRef.current) return;
      const container = containerRef.current;
      const badges = Array.from(container.querySelectorAll('.tag-badge')) as HTMLElement[];
      if (badges.length === 0) {
        setTimeout(checkOverflow, 50);
        return;
      }
      
      const firstBadgeTop = badges[0]?.offsetTop;
      let lastVisibleIndex = badges.length;

      // Find where tags overflow to second line
      for (let i = 0; i < badges.length; i++) {
        if (badges[i].offsetTop > firstBadgeTop) {
          lastVisibleIndex = i;
          break;
        }
      }

      // If all tags fit, no need for "..." button
      if (lastVisibleIndex === badges.length) {
        setVisibleCount(badges.length);
        return;
      }

      // Calculate available width and check if we need to reduce for "..." button
      const containerWidth = container.offsetWidth;
      const moreButtonWidth = 40; // Approximate width for "..." button
      
      // Calculate total width of visible tags
      let totalWidth = 0;
      let adjustedIndex = lastVisibleIndex;
      
      for (let i = 0; i < lastVisibleIndex; i++) {
        totalWidth += badges[i].offsetWidth + 8; // 8px gap
      }
      
      // If visible tags + button would overflow, reduce by 1
      if (totalWidth + moreButtonWidth > containerWidth) {
        adjustedIndex = Math.max(1, lastVisibleIndex - 1);
      }
      
      setVisibleCount(adjustedIndex);
    };
    setVisibleCount(999);
    const timer = setTimeout(checkOverflow, 100);
    window.addEventListener('resize', checkOverflow);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', checkOverflow);
    };
  }, [allTags.length, restaurant.id]);
  const visibleTags = allTags.slice(0, visibleCount);
  const hiddenTags = allTags.slice(visibleCount);
  const hasMore = hiddenTags.length > 0;
  return <div className="flex items-center gap-2 -mt-1">
      <div ref={containerRef} className="flex gap-2 flex-wrap flex-1">
        {visibleTags.map(tag => <Badge key={tag.key} variant={tag.variant} className="text-xs whitespace-nowrap tag-badge" style={tag.color ? {
        backgroundColor: tag.color,
        color: 'white'
      } : undefined}>
            {tag.label}
          </Badge>)}
      </div>
      {hasMore && <Popover>
          <PopoverTrigger asChild>
            <Button variant="ghost" size="sm" className="h-6 px-2 text-muted-foreground hover:text-foreground flex-shrink-0">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto max-w-80">
            <div className="flex flex-wrap gap-2">
              {hiddenTags.map(tag => <Badge key={tag.key} variant={tag.variant} className="text-xs" style={tag.color ? {
            backgroundColor: tag.color,
            color: 'white'
          } : undefined}>
                  {tag.label}
                </Badge>)}
            </div>
          </PopoverContent>
        </Popover>}
    </div>;
};
const Restaurants = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { tab: urlTab } = useParams<{ tab?: string }>();
  const queryClient = useQueryClient();
  const {
    t,
    i18n
  } = useTranslation();
  const {
    toast
  } = useToast();
  const {
    localizeRestaurant,
    getLocalizedField,
  } = useLocalizedContent();
  const isMobile = useIsMobile();
  const { requireLogin } = useLoginRequired();
  const { country: detectedCountry } = useUserCountry();
  const [searchQuery, setSearchQuery] = useState(() => {
    const saved = sessionStorage.getItem('restaurants-filter-search');
    if (saved) return saved;
    return "";
  });
  const [translations, setTranslations] = useState<Record<string, string> | null>(null);
  const [activityTranslations, setActivityTranslations] = useState<Record<string, string>>({});
  type TemplateTab = "landmark" | "hotel" | "embassy" | "michelin" | "food";
  const validTabs: TemplateTab[] = ["landmark", "hotel", "embassy", "michelin", "food"];
  // Map legacy tabs to "food"
  const legacyTabMap: Record<string, TemplateTab> = { historic: "food", all: "food" };
  const resolvedUrlTab = legacyTabMap[urlTab as string] || (validTabs.includes(urlTab as any) ? (urlTab as TemplateTab) : null);
  const [templateFilter, setTemplateFilterState] = useState<TemplateTab>(() => {
    if (resolvedUrlTab) return resolvedUrlTab;
    const params = new URLSearchParams(window.location.search);
    if (params.get('nearId') || params.get('nearLat')) return "food";
    const saved = sessionStorage.getItem('restaurants-filter-template');
    if (saved) {
      return (legacyTabMap[saved] || (validTabs.includes(saved as any) ? saved : "landmark")) as TemplateTab;
    }
    return "landmark";
  });

  // Sync URL tab → state
  useEffect(() => {
    if (resolvedUrlTab && resolvedUrlTab !== templateFilter) {
      setTemplateFilterState(resolvedUrlTab);
    }
  }, [resolvedUrlTab]);

  // Navigate on tab change
  const setTemplateFilter = useCallback((value: TemplateTab) => {
    setTemplateFilterState(value);
    if (value !== "michelin") setMichelinStarFilter(null);
    const basePath = `/restaurants/${value}`;
    const qs = searchParams.toString();
    navigate(qs ? `${basePath}?${qs}` : basePath, { replace: true });
  }, [navigate, searchParams]);
  const [selectedTypes, setSelectedTypes] = useState<string[]>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-types');
    if (saved) {
      try { return JSON.parse(saved); } catch { return []; }
    }
    return [];
  });
  const [selectedCountry, setSelectedCountry] = useState<string | null>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-country');
    if (saved) return saved;
    return null;
  });
  const [selectedDistrict, setSelectedDistrict] = useState<string | null>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-district');
    if (saved) return saved;
    return null;
  });
  const [countrySearch, setCountrySearch] = useState("");
  const [districtSearch, setDistrictSearch] = useState("");
  const [verifiedFilter, setVerifiedFilter] = useState<"all" | "verified" | "unverified">(() => {
    const saved = sessionStorage.getItem('restaurants-filter-verified');
    if (saved) return saved as "all" | "verified" | "unverified";
    return "all";
  });
  const [selectedActivity, setSelectedActivity] = useState<string | null>(null);
  const [michelinStarFilter, setMichelinStarFilter] = useState<string | null>(null);
  const [activityRestaurantIds, setActivityRestaurantIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<"list" | "map">("list");
  const [listColumns, setListColumns] = useState<1 | 2>(() => {
    const saved = localStorage.getItem('restaurant-list-columns');
    return (saved === '1' ? 1 : 2) as 1 | 2;
  });
  const [radiusFilter, setRadiusFilter] = useState<number | null>(() => {
    const nearRadius = searchParams.get('nearRadius');
    return nearRadius ? parseFloat(nearRadius) : null;
  });
  // Landmark-based nearby mode
  const nearLandmarkNameRaw = searchParams.get('nearName');
  const nearLandmarkId = searchParams.get('nearId');
  const { data: nearLandmarkData } = useRestaurant(nearLandmarkId || '');
  const nearLandmarkName = useMemo(() => {
    if (nearLandmarkData) {
      const lang = i18n.language;
      if (lang === 'en' && nearLandmarkData.name_en) return nearLandmarkData.name_en;
      if (lang === 'pt' && nearLandmarkData.name_pt) return nearLandmarkData.name_pt;
      if (lang === 'zh') return nearLandmarkData.name;
      // For other languages, prefer name_en as fallback
      return nearLandmarkData.name_en || nearLandmarkData.name;
    }
    return nearLandmarkNameRaw ? decodeURIComponent(nearLandmarkNameRaw) : null;
  }, [nearLandmarkData, nearLandmarkNameRaw, i18n.language]);
  const nearLandmarkLocation = useMemo(() => {
    const nearLat = searchParams.get('nearLat');
    const nearLng = searchParams.get('nearLng');
    if (nearLat && nearLng) return { lat: parseFloat(nearLat), lng: parseFloat(nearLng) };
    return null;
  }, [searchParams]);
  const [userLocation, setUserLocation] = useState<{
    lat: number;
    lng: number;
  } | null>(() => {
    const nearLat = searchParams.get('nearLat');
    const nearLng = searchParams.get('nearLng');
    if (nearLat && nearLng) {
      return { lat: parseFloat(nearLat), lng: parseFloat(nearLng) };
    }
    const saved = localStorage.getItem('restaurant-user-location');
    if (saved) {
      try { return JSON.parse(saved); } catch { return null; }
    }
    return null;
  });
  // Real user GPS location (separate from landmark-based userLocation)
  const [realUserGps, setRealUserGps] = useState<{ lat: number; lng: number } | null>(null);
  const [sortByDistance, setSortByDistance] = useState(() => {
    if (searchParams.get('nearLat')) return true;
    return localStorage.getItem('restaurant-sort-by-distance') === 'true';
  });
  const [showAllTypes, setShowAllTypes] = useState(false);
  const [filterOpen, setFilterOpen] = useState(false);
  const [showAllActivities, setShowAllActivities] = useState(false);
  const [showNavigationDialog, setShowNavigationDialog] = useState(false);
  const [showLocationDialog, setShowLocationDialog] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [navigationTarget, setNavigationTarget] = useState<{ lat: number; lng: number; name: string } | null>(null);
  const [storyDialog, setStoryDialog] = useState<{ id?: string; name: string; story: string; address?: string; image_url?: string | null; photo_story_zh?: string | null; photo_story_en?: string | null; photo_story_pt?: string | null } | null>(null);
  const [verifiedDialog, setVerifiedDialog] = useState(false);
  const [claimDialog, setClaimDialog] = useState<{ id: string; name: string; address?: string } | null>(null);
  const {
    user
  } = useAuth();

  // AI Search
  const { search: aiSearch, isSearching: isAISearching, aiResults, aiError, clearResults: clearAIResults } = useAISearchRestaurants();
  const [aiSearchQuery, setAiSearchQuery] = useState("");
  const isAIMode = !!aiResults || isAISearching;
  
  // Server-side paginated data for list view
  const [currentPage, setCurrentPage] = useState(0);
  const PAGE_SIZE = 12;
  
  const paginatedFilters = {
    search: searchQuery || undefined,
    country: selectedCountry,
    district: selectedDistrict,
    template: templateFilter === "food" ? "all" : templateFilter,
    verified: verifiedFilter,
    types: selectedTypes,
    activityId: selectedActivity,
    userLat: userLocation?.lat,
    userLng: userLocation?.lng,
    radiusKm: radiusFilter,
    sortByDistance,
    michelinStar: michelinStarFilter,
  };
  
  const {
    data: paginatedResult,
    isLoading: isListLoading,
  } = useRestaurantsPaginated(paginatedFilters, currentPage, PAGE_SIZE);
  
  // For map view, fetch all matching restaurants (only when map is active)
  const {
    data: allRestaurantsRaw,
    isLoading: isMapLoading,
  } = useRestaurants(searchQuery, selectedTypes.length > 0 ? selectedTypes.join(',') : undefined);
  
  const isLoading = viewMode === "map" ? isMapLoading : isListLoading;
  
  const {
    data: favoriteIds = []
  } = useFavorites();
  const {
    data: restaurantTypes = []
  } = useRestaurantTypes();
  const {
    data: dynamicRestaurantTypes = []
  } = useRestaurantTypesByTab(templateFilter);
  const { data: allCountries = [] } = useRestaurantCountries();
  const { data: districts = [] } = useRestaurantDistricts(selectedCountry, templateFilter);

  // Map DB country names to i18n keys, and filter to only website-supported countries
  const SUPPORTED_COUNTRY_MAP: Record<string, string> = {
    "Portugal": "Portugal", "Spain": "Spain", "France": "France",
    "Germany": "Germany", "Italy": "Italy", "UK": "United Kingdom",
    "Japan": "Japan", "Korea": "South Korea", "China": "China",
    "USA": "United States", "Saudi Arabia": "Saudi Arabia",
    "Mexico": "Mexico", "Vietnam": "Vietnam", "Singapore": "Singapore",
  };
  const countries = allCountries.filter(c => c in SUPPORTED_COUNTRY_MAP);
  const getCountryI18nKey = (dbCountry: string) => SUPPORTED_COUNTRY_MAP[dbCountry] || dbCountry;
  const getCountryDisplayName = (dbCountry: string) => t(`countries.${getCountryI18nKey(dbCountry)}`, dbCountry);
  const {
    data: activities = []
  } = useActivities();
  const { data: activityRestaurantCounts = {} } = useActivityRestaurantCounts();


  // Scroll position restoration for back navigation
  const isRestoringScroll = useRef(false);
  const savedScrollTarget = useRef<number | null>(null);

  // On mount: read saved scroll position (only if returning from detail)
  useEffect(() => {
    const fromDetail = sessionStorage.getItem('restaurants-nav-from-detail');
    if (fromDetail) {
      sessionStorage.removeItem('restaurants-nav-from-detail');
      const saved = sessionStorage.getItem('restaurants-scroll-pos');
      if (saved) {
        savedScrollTarget.current = parseInt(saved, 10);
        isRestoringScroll.current = true;
      }
    } else {
      // Fresh navigation - only clear scroll position, keep filters
      sessionStorage.removeItem('restaurants-scroll-pos');
    }
  }, []);

  // Continuously save scroll position (skip during restoration)
  useEffect(() => {
    const handleScroll = () => {
      if (isRestoringScroll.current) return;
      sessionStorage.setItem('restaurants-scroll-pos', String(window.scrollY));
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  // Restore scroll after data loads
  useEffect(() => {
    if (savedScrollTarget.current != null && !isLoading) {
      const target = savedScrollTarget.current;
      savedScrollTarget.current = null;
      const timer = setTimeout(() => {
        window.scrollTo(0, target);
        setTimeout(() => { isRestoringScroll.current = false; }, 100);
      }, 150);
      return () => clearTimeout(timer);
    }
  }, [isLoading]);


  const handleRefresh = useCallback(async () => {
    // Clear caches to force fresh fetch
    queryClient.removeQueries({ queryKey: ['restaurants'] });
    queryClient.removeQueries({ queryKey: ['restaurants-paginated'] });
    queryClient.removeQueries({ queryKey: ['activities'] });
    queryClient.removeQueries({ queryKey: ['restaurantTypes'] });
    queryClient.removeQueries({ queryKey: ['favorites'] });
    queryClient.removeQueries({ queryKey: ['favorite-ids'] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['restaurants'] }),
      queryClient.invalidateQueries({ queryKey: ['restaurants-paginated'] }),
      queryClient.invalidateQueries({ queryKey: ['activities'] }),
      queryClient.invalidateQueries({ queryKey: ['restaurantTypes'] }),
      queryClient.invalidateQueries({ queryKey: ['favorites'] }),
      queryClient.invalidateQueries({ queryKey: ['favorite-ids'] }),
    ]);
  }, [queryClient]);

  // Filter activities to only show those with at least 1 restaurant
  const activitiesWithRestaurants = activities.filter(activity => (activityRestaurantCounts[activity.id] || 0) > 0);

  // Auto-translate activity badge texts for non-zh/en/pt languages
  const activityTranslationLangRef = useRef('');
  useEffect(() => {
    const lang = i18n.language;
    if (['zh', 'en', 'pt'].includes(lang) || activitiesWithRestaurants.length === 0) {
      if (['zh', 'en', 'pt'].includes(lang)) setActivityTranslations({});
      return;
    }

    // Skip if already translated for this language
    if (activityTranslationLangRef.current === lang && Object.keys(activityTranslations).length > 0) return;
    activityTranslationLangRef.current = lang;

    const textsToTranslate = activitiesWithRestaurants.map(a => 
      a.badge_text_en || a.title_en
    );

    const separator = "\n---ITEM_SEPARATOR---\n";
    const combinedText = textsToTranslate.join(separator);

    supabase.functions.invoke('translate-content', {
      body: { text: combinedText, targetLang: lang }
    }).then(({ data, error }) => {
      if (error || !data?.translatedText) return;
      const parts = data.translatedText.split(/---ITEM_SEPARATOR---/);
      const map: Record<string, string> = {};
      activitiesWithRestaurants.forEach((a, i) => {
        map[a.id] = (parts[i] || textsToTranslate[i]).trim();
      });
      setActivityTranslations(map);
    });
  }, [activitiesWithRestaurants.length, i18n.language]);

  const toggleFavorite = useToggleFavorite();
  const handleToggleFavorite = (restaurantId: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!user) {
      return;
    }
    toggleFavorite.mutate(restaurantId);
  };
  const handleTypeFilter = (type: string) => {
    setSelectedTypes(prev => {
      if (prev.includes(type)) {
        // Remove type if already selected
        return prev.filter(t => t !== type);
      } else {
        // Add type to selection
        return [...prev, type];
      }
    });
  };
  const handleRequestLocation = () => {
    if (sortByDistance) {
      // Already sorting by distance — toggle it off
      setSortByDistance(false);
      setUserLocation(null);
      localStorage.removeItem('restaurant-user-location');
      localStorage.removeItem('restaurant-sort-by-distance');
      return;
    }
    setShowLocationDialog(true);
  };
  
  // Persist location sorting preference
  useEffect(() => {
    if (userLocation) {
      localStorage.setItem('restaurant-user-location', JSON.stringify(userLocation));
    }
  }, [userLocation]);

  useEffect(() => {
    localStorage.setItem('restaurant-sort-by-distance', String(sortByDistance));
  }, [sortByDistance]);

  // Auto-locate on page mount
  useEffect(() => {
    // Always try to get location when entering the page
    setIsLocating(true);
    getUserLocation().then(position => {
      const gps = {
        lat: position.coords.latitude,
        lng: position.coords.longitude
      };
      // If in landmark mode, keep userLocation as landmark coords for distance sorting
      // but store real GPS separately for showing user-to-restaurant distance
      if (nearLandmarkLocation) {
        setRealUserGps(gps);
      } else {
        setUserLocation(gps);
        setSortByDistance(true);
      }
    }).catch(() => {
      // Silently handle — keep any cached location
    }).finally(() => {
      setIsLocating(false);
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Auto-fill country filter from detected user country (only on fresh navigation)
  const hasAutoFilledCountry = useRef(false);
  useEffect(() => {
    if (hasAutoFilledCountry.current) return;
    if (nearLandmarkLocation) { hasAutoFilledCountry.current = true; return; } // Skip auto-fill in landmark mode
    if (!detectedCountry) return;
    // Don't override if user already selected a country (e.g. restored from session)
    if (selectedCountry) { hasAutoFilledCountry.current = true; return; }
    setSelectedCountry(detectedCountry);
    hasAutoFilledCountry.current = true;
  }, [detectedCountry, selectedCountry, nearLandmarkLocation]);

  const requestLocation = async () => {
    setShowLocationDialog(false);
    setIsLocating(true);
    try {
      const position = await getUserLocation();
      setUserLocation({
        lat: position.coords.latitude,
        lng: position.coords.longitude
      });
      setSortByDistance(true);
      toast({
        title: t("restaurants.locationEnabled"),
        description: t("restaurants.sortByDistance")
      });
    } catch (error: any) {
      console.error("Location error:", error);
      if (error?.code === 1) {
        // PERMISSION_DENIED
        toast({
          title: t("location.permissionDenied", "位置权限被拒绝"),
          description: t("location.permissionDeniedDesc", "请在浏览器设置中允许位置访问后重试"),
          variant: "destructive",
        });
      } else {
        toast({
          title: t("location.error", "获取位置失败"),
          description: t("location.errorDesc", "请检查网络或定位服务是否开启"),
          variant: "destructive",
        });
      }
    } finally {
      setIsLocating(false);
    }
  };
  const handleRadiusChange = (radius: number | null) => {
    setRadiusFilter(radius);
    if (radius && !userLocation) {
      requestLocation();
    }
  };
  const handleActivityFilter = async (activityId: string) => {
    if (selectedActivity === activityId) {
      setSelectedActivity(null);
      setActivityRestaurantIds([]);
    } else {
      setSelectedActivity(activityId);
      // Fetch restaurants for this activity
      const {
        data,
        error
      } = await supabase.from("activity_restaurants").select("restaurant_id").eq("activity_id", activityId);
      if (error) {
        console.error("Error fetching activity restaurants:", error);
        setActivityRestaurantIds([]);
      } else {
        setActivityRestaurantIds(data.map(ar => ar.restaurant_id));
      }
    }
  };

  // Removed automatic location request - now manual only

  // === List view: accumulate loaded pages ===
  const [loadedPages, setLoadedPages] = useState<Record<number, any[]>>({});
  
  // Target page for catch-up restoration (when returning from detail on page 2+)
  const restoreTargetPage = useRef<number | null>((() => {
    const saved = sessionStorage.getItem('restaurants-filter-page');
    if (saved) {
      const page = parseInt(saved, 10);
      return page > 0 ? page : null;
    }
    return null;
  })());

  // Track the filter signature to detect filter changes within the data effect
  const filterSignature = useMemo(() => 
    JSON.stringify([searchQuery, selectedTypes, selectedActivity, radiusFilter, sortByDistance, templateFilter, selectedCountry, selectedDistrict, verifiedFilter, michelinStarFilter]),
    [searchQuery, selectedTypes, selectedActivity, radiusFilter, sortByDistance, templateFilter, selectedCountry, selectedDistrict, verifiedFilter, michelinStarFilter]
  );
  const lastFilterSignature = useRef(filterSignature);
  
  useEffect(() => {
    if (!paginatedResult?.data) return;
    
    const filtersChanged = lastFilterSignature.current !== filterSignature;
    lastFilterSignature.current = filterSignature;
    
    if (filtersChanged || currentPage === 0) {
      // Filters changed or first page: reset all pages with fresh data
      setLoadedPages({ 0: paginatedResult.data });
    } else {
      // Subsequent page: append
      setLoadedPages(prev => ({ ...prev, [currentPage]: paginatedResult.data }));
    }
    
    // Catch-up: if we haven't reached the target page yet, advance to next page
    const target = restoreTargetPage.current;
    if (typeof target === 'number' && target > 0 && currentPage < target) {
      setCurrentPage(prev => prev + 1);
    } else if (typeof target === 'number' && currentPage >= target) {
      restoreTargetPage.current = null;
    }
  }, [paginatedResult, currentPage, filterSignature]);

  const displayedRestaurants = useMemo(() => {
    const allData: any[] = [];
    const pageKeys = Object.keys(loadedPages).map(Number).sort((a, b) => a - b);
    for (const pageKey of pageKeys) {
      for (const restaurant of loadedPages[pageKey]) {
        const loc = localizeRestaurant(restaurant);
        allData.push({ ...loc, distance: (restaurant as any).distance_km });
      }
    }
    return allData;
  }, [loadedPages, localizeRestaurant, i18n.language]);

  // Auto-translate restaurant names for non-base languages (not zh/en/pt)
  useAutoTranslateNames(displayedRestaurants, setTranslations);

  const totalCount = paginatedResult?.total || 0;
  const hasMore = (currentPage + 1) * PAGE_SIZE < totalCount;
  const displayedCount = displayedRestaurants.length;

  const loadMore = () => setCurrentPage(prev => prev + 1);

  // === Map view: still needs all filtered data for markers ===
  const mapProcessedRestaurants = allRestaurantsRaw?.map(restaurant => {
    const localized = localizeRestaurant(restaurant);
    if (userLocation) {
      const distance = calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
      return { ...localized, distance };
    }
    return localized;
  }) || [];

  // Apply client-side filters for map view (server-side for list view)
  const mapFilteredRestaurants = mapProcessedRestaurants.filter(r => {
    if (selectedCountry && (r as any).country !== selectedCountry) return false;
    if (selectedDistrict && (r as any).district !== selectedDistrict) return false;
    if (templateFilter !== "food") {
      const embassyTypes = ['embassy', '大使馆', 'Embassy'];
      const isEmbassy = (r as any).type?.some((t: string) => embassyTypes.includes(t) || t.toLowerCase().includes('embassy'));
      if (templateFilter === "landmark" && (r.template !== "landmark" || isEmbassy)) return false;
      if (templateFilter === "embassy" && (r.template !== "landmark" || !isEmbassy)) return false;
      if (templateFilter === "hotel" && r.template !== "hotel") return false;
    }
    if (verifiedFilter === "verified" && (r as any).store_level !== "complete") return false;
    if (verifiedFilter === "unverified" && (r as any).store_level === "complete") return false;
    if (selectedActivity && !activityRestaurantIds.includes(r.id)) return false;
    if (radiusFilter && userLocation && r.distance && r.distance > radiusFilter) return false;
    return true;
  });


  // Reset page when filters change
  const hasMountedRef = useRef(false);
  useEffect(() => {
    if (!hasMountedRef.current) {
      hasMountedRef.current = true;
      return;
    }
    setCurrentPage(0);
  }, [searchQuery, selectedTypes, selectedActivity, radiusFilter, sortByDistance, templateFilter, selectedCountry, selectedDistrict, verifiedFilter, michelinStarFilter]);

  // Persist filters to sessionStorage whenever they change
  useEffect(() => {
    sessionStorage.setItem('restaurants-filter-search', searchQuery);
    sessionStorage.setItem('restaurants-filter-template', templateFilter);
    sessionStorage.setItem('restaurants-filter-types', JSON.stringify(selectedTypes));
    sessionStorage.setItem('restaurants-filter-country', selectedCountry || '');
    sessionStorage.setItem('restaurants-filter-district', selectedDistrict || '');
    sessionStorage.setItem('restaurants-filter-verified', verifiedFilter);
  }, [searchQuery, templateFilter, selectedTypes, selectedCountry, selectedDistrict, verifiedFilter]);


  const handleRestaurantClick = (restaurant: any) => {
    sessionStorage.setItem('restaurants-nav-from-detail', '1');
    sessionStorage.setItem('restaurants-filter-page', String(currentPage));
    navigate(`/restaurant/${restaurant.id}`);
  };
  const pageContent = (
    <div className={`bg-secondary/20 animate-fade-in overflow-x-hidden ${viewMode === "map" ? "h-screen flex flex-col overflow-hidden" : "min-h-screen py-8 px-3 sm:px-4"}`}>
      <div className={`${viewMode === "map" ? "flex flex-col h-full" : "container mx-auto max-w-7xl"}`}>
        {/* Header */}
        <div className={`${viewMode === "map" ? "px-4 pt-4 pb-2 flex-shrink-0" : "mb-8"}`}>
          <div className="flex items-center justify-between mb-4">
            <h1 className={`text-2xl sm:text-3xl md:text-4xl font-medium text-primary ${viewMode === "map" ? "hidden md:block" : ""}`}>{t("restaurants.title")}</h1>
          </div>
          
          {/* Template Tabs - Mobile: pill style, Desktop: underline style */}
          {isMobile ? (
            <Tabs value={templateFilter} onValueChange={(v) => setTemplateFilter(v as TemplateTab)} className="mb-4">
              <TabsList className="w-full bg-primary/8 border border-primary/20 p-0.5 rounded-lg h-auto flex overflow-x-auto scrollbar-none">
                <TabsTrigger value="landmark" className="flex-shrink-0 px-2 py-1.5 text-[11px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-md text-foreground/60 hover:text-primary font-semibold whitespace-nowrap">{t("restaurants.tabLandmark")}</TabsTrigger>
                <TabsTrigger value="hotel" className="flex-shrink-0 px-2 py-1.5 text-[11px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-md text-foreground/60 hover:text-primary font-semibold whitespace-nowrap">{t("restaurants.tabHotel")}</TabsTrigger>
                <TabsTrigger value="embassy" className="flex-shrink-0 px-2 py-1.5 text-[11px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-md text-foreground/60 hover:text-primary font-semibold whitespace-nowrap">{t("restaurants.tabEmbassy")}</TabsTrigger>
                <TabsTrigger value="michelin" className="flex-shrink-0 px-2 py-1.5 text-[11px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-md text-foreground/60 hover:text-primary font-semibold whitespace-nowrap">{t("restaurants.tabMichelin")}</TabsTrigger>
                <TabsTrigger value="food" className="flex-shrink-0 px-2 py-1.5 text-[11px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-md text-foreground/60 hover:text-primary font-semibold whitespace-nowrap">{t("restaurants.tabFood")}</TabsTrigger>
              </TabsList>
              <p className="text-[10px] text-muted-foreground mt-1.5 px-1 leading-relaxed">{t(`restaurants.tabDesc${templateFilter.charAt(0).toUpperCase() + templateFilter.slice(1)}` as any)}</p>
            </Tabs>
          ) : (
            <div className="mb-5 border-b border-border/60">
              <nav className="flex gap-1">
                {([
                  { value: "landmark", icon: Landmark, label: t("restaurants.tabLandmark") },
                  { value: "hotel", icon: Building2, label: t("restaurants.tabHotel") },
                  { value: "embassy", icon: Flag, label: t("restaurants.tabEmbassy") },
                  { value: "michelin", icon: Star, label: t("restaurants.tabMichelin") },
                  { value: "food", icon: MapPin, label: t("restaurants.tabFood") },
                ] as const).map(({ value, icon: Icon, label }) => (
                  <button
                    key={value}
                    onClick={() => setTemplateFilter(value as TemplateTab)}
                    className={`relative flex items-center gap-1.5 px-4 py-2.5 text-sm font-medium transition-colors whitespace-nowrap ${
                      templateFilter === value
                        ? "text-primary"
                        : "text-muted-foreground hover:text-foreground"
                    }`}
                  >
                    <Icon className="h-4 w-4" />
                    {label}
                    {templateFilter === value && (
                      <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary rounded-t-full" />
                    )}
                  </button>
                ))}
              </nav>
              <p className="text-xs text-muted-foreground mt-1 mb-3 px-4 leading-relaxed">{t(`restaurants.tabDesc${templateFilter.charAt(0).toUpperCase() + templateFilter.slice(1)}` as any)}</p>
            </div>
          )}
          
          
          <div className="flex flex-col gap-2">
            {/* Search + Action Buttons - all h-9 unified */}
            <div className="flex gap-1.5 items-center">
              <div className="relative flex-1 min-w-0 md:max-w-md">
                <Sparkles className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-primary/60 z-10 pointer-events-none" />
                <Input 
                  placeholder={t("restaurants.aiSearchPlaceholder")} 
                  value={aiSearchQuery} 
                  onChange={e => {
                    setAiSearchQuery(e.target.value);
                    if (!e.target.value.trim()) {
                      clearAIResults();
                    }
                  }}
                  onKeyDown={e => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      const q = aiSearchQuery.trim();
                      if (q.length >= 2) {
                        aiSearch(q, userLocation?.lat, userLocation?.lng, templateFilter);
                      }
                    }
                  }}
                  className="pl-9 pr-10 h-9"
                />
                {isAISearching ? (
                  <div className="absolute right-3 top-1/2 -translate-y-1/2 z-10">
                    <Loader2 className="h-4 w-4 text-primary" style={{ animation: "spin 1s linear infinite" }} />
                  </div>
                ) : (aiSearchQuery || isAIMode) ? (
                  <button
                    onClick={() => {
                      setAiSearchQuery("");
                      clearAIResults();
                    }}
                    className="absolute right-3 top-1/2 -translate-y-1/2 z-10 text-muted-foreground hover:text-foreground"
                  >
                    <X className="h-4 w-4" />
                  </button>
                ) : null}
              </div>
              
              {/* Location Button */}
              <Button 
                variant={userLocation ? "default" : "outline"} 
                size="icon" 
                onClick={handleRequestLocation}
                disabled={isLocating}
                className="h-9 w-9 flex-shrink-0"
                title={isLocating ? t("restaurants.locating", "定位中...") : t("restaurants.getLocation")}
              >
                {isLocating ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Navigation className="h-4 w-4" />
                )}
              </Button>
              
              {/* View Toggle Group */}
              <div className="inline-flex h-9 items-center justify-center rounded-md bg-muted p-0.5 text-muted-foreground flex-shrink-0">
                <button 
                  onClick={() => {
                    if (viewMode === "list") {
                      if (isMobile) {
                        const newColumns = listColumns === 2 ? 1 : 2;
                        setListColumns(newColumns);
                        localStorage.setItem('restaurant-list-columns', String(newColumns));
                      }
                    } else {
                      setViewMode("list");
                    }
                  }} 
                  className={`inline-flex items-center justify-center rounded-sm px-2.5 py-1.5 transition-all ${
                    viewMode === "list" ? 'bg-background text-foreground shadow-sm' : ''
                  }`}
                >
                  {viewMode === "list" && isMobile && listColumns === 1 ? (
                    <LayoutGrid className="h-4 w-4" />
                  ) : (
                    <List className="h-4 w-4" />
                  )}
                </button>
                <button 
                  onClick={() => setViewMode("map")} 
                  className={`inline-flex items-center justify-center rounded-sm px-2.5 py-1.5 transition-all ${
                    viewMode === "map" ? 'bg-background text-foreground shadow-sm' : ''
                  }`}
                >
                  <Map className="h-4 w-4" />
                </button>
              </div>

              {/* Filter Sheet Trigger */}
              <Sheet open={filterOpen} onOpenChange={setFilterOpen}>
                <SheetTrigger asChild>
                  <Button 
                    variant="outline" 
                    size="icon" 
                    className="h-9 w-9 flex-shrink-0 relative"
                  >
                    <Filter className="h-4 w-4" />
                    {(selectedActivity || radiusFilter || selectedCountry || selectedDistrict || verifiedFilter !== "all" || selectedTypes.length > 0 || michelinStarFilter) && (
                      <span className="absolute -top-1 -right-1 h-4 w-4 rounded-full bg-primary text-primary-foreground text-[10px] flex items-center justify-center font-medium">
                        {(selectedActivity ? 1 : 0) + (radiusFilter ? 1 : 0) + (selectedCountry ? 1 : 0) + (selectedDistrict ? 1 : 0) + (verifiedFilter !== "all" ? 1 : 0) + (selectedTypes.length > 0 ? 1 : 0) + (michelinStarFilter ? 1 : 0)}
                      </span>
                    )}
                  </Button>
                </SheetTrigger>
                <SheetContent side={isMobile ? "bottom" : "right"} className={`${isMobile ? 'h-[85vh] rounded-t-2xl' : 'w-[400px]'} p-0 flex flex-col`}>
                  {/* Sheet Header */}
                  <div className="flex items-center justify-between px-5 py-4 pr-12 border-b border-border/50">
                    <SheetTitle className="text-lg font-semibold">{t("restaurants.filter")}</SheetTitle>
                    {(selectedActivity || radiusFilter || selectedCountry || selectedDistrict || verifiedFilter !== "all" || selectedTypes.length > 0 || michelinStarFilter) && (
                      <Button
                        variant="ghost"
                        size="sm"
                        className="h-8 px-3 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                        onClick={() => {
                          setSelectedTypes([]);
                          setSelectedActivity(null);
                          setActivityRestaurantIds([]);
                          setRadiusFilter(null);
                          setSelectedCountry(null);
                          setSelectedDistrict(null);
                          setVerifiedFilter("all");
                          setMichelinStarFilter(null);
                        }}
                      >
                        <X className="w-3.5 h-3.5 mr-1" />
                        {t("common.actions.clearFilter")}
                      </Button>
                    )}
                  </div>

                  {/* Sheet Body - Scrollable */}
                  <div className="flex-1 overflow-y-auto px-5 py-4 space-y-6">

                    {/* Michelin Star Filter - only in michelin tab */}
                    {templateFilter === "michelin" && (
                      <>
                        <div className="space-y-3">
                          <div className="flex items-center justify-between">
                            <span className="text-sm font-semibold text-foreground">{t("restaurants.michelinLevel", "米其林级别")}</span>
                            {michelinStarFilter && (
                              <Button
                                variant="ghost"
                                size="sm"
                                className="h-7 px-2 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                                onClick={() => setMichelinStarFilter(null)}
                              >
                                <X className="w-3 h-3 mr-1" />
                                {t("common.actions.clear")}
                              </Button>
                            )}
                          </div>
                          <div className="flex gap-2 flex-wrap">
                            {[
                              { value: null, label: t("restaurants.michelinAll", "全部") },
                              { value: "3", label: t("restaurants.michelin3Star", "三星 ⭐⭐⭐") },
                              { value: "2", label: t("restaurants.michelin2Star", "二星 ⭐⭐") },
                              { value: "1", label: t("restaurants.michelin1Star", "一星 ⭐") },
                              { value: "bib_gourmand", label: t("restaurants.michelinBib", "必比登") },
                              { value: "selected", label: t("restaurants.michelinSelected", "入选") },
                            ].map(({ value, label }) => (
                              <button
                                key={value ?? "all"}
                                onClick={() => setMichelinStarFilter(value)}
                                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                                  michelinStarFilter === value
                                    ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                                    : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                                }`}
                              >
                                {label}
                              </button>
                            ))}
                          </div>
                        </div>
                        <Separator />
                      </>
                    )}
                     
                    {/* Type Filter - Grouped */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-semibold text-foreground">{t("restaurants.types", "类型")}</span>
                        {selectedTypes.length > 0 && (
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-7 px-2 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                            onClick={() => setSelectedTypes([])}
                          >
                            <X className="w-3 h-3 mr-1" />
                            {t("common.actions.clear")}
                          </Button>
                        )}
                      </div>
                      {groupTypesByCategory(dynamicRestaurantTypes, templateFilter).map((group) => (
                        <div key={group.key} className="space-y-1.5">
                          <span className="text-xs font-medium text-muted-foreground">
                            {group.label[i18n.language] || group.label.en}
                          </span>
                          <div className="flex gap-2 flex-wrap">
                            {group.tags.map((type) => (
                              <button
                                key={type}
                                onClick={() => handleTypeFilter(type)}
                                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                                  selectedTypes.includes(type)
                                    ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                                    : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                                }`}
                              >
                                {getTypeDisplayLabel(type, i18n.language)}
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>

                    <Separator />

                    {/* Activity Filter */}
                    {activitiesWithRestaurants.length > 0 && (
                      <>
                        <div className="space-y-3">
                          <div className="flex items-center justify-between">
                            <span className="text-sm font-semibold text-foreground">{t("nav.activities")}</span>
                            <div className="flex items-center gap-2">
                              {selectedActivity && (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  className="h-7 px-2 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                                  onClick={() => {
                                    setSelectedActivity(null);
                                    setActivityRestaurantIds([]);
                                  }}
                                >
                                  <X className="w-3 h-3 mr-1" />
                                  {t("common.actions.clear")}
                                </Button>
                              )}
                              {activitiesWithRestaurants.length > 6 && (
                                <Button
                                  variant="link"
                                  size="sm"
                                  className="h-auto p-0 text-xs text-primary hover:text-primary/80"
                                  onClick={() => setShowAllActivities(!showAllActivities)}
                                >
                                  {showAllActivities ? t("common.showLess") : t("common.showMore")}
                                </Button>
                              )}
                            </div>
                          </div>
                          <div className="flex gap-2 flex-wrap">
                            {(showAllActivities ? activitiesWithRestaurants : activitiesWithRestaurants.slice(0, 6)).map((activity) => {
                              const lang = i18n.language;
                              const badgeText = activityTranslations[activity.id] 
                                || (lang === 'zh' 
                                  ? (activity.badge_text_zh || activity.title_zh)
                                  : lang === 'pt' 
                                  ? (activity.badge_text_pt || activity.title_pt)
                                  : (activity.badge_text_en || activity.title_en));
                              return (
                                <button
                                  key={activity.id}
                                  onClick={() => handleActivityFilter(activity.id)}
                                  className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                                    selectedActivity === activity.id 
                                      ? 'bg-primary text-primary-foreground border-primary shadow-sm' 
                                      : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                                  }`}
                                >
                                  {badgeText}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                        <Separator />
                      </>
                    )}
                  </div>

                  {/* Sheet Footer - Apply Button */}
                  <div className="px-5 py-4 border-t border-border/50 bg-background">
                    <Button className="w-full" onClick={() => setFilterOpen(false)}>
                      {t("common.actions.apply", "应用筛选")} ({totalCount} {t("restaurants.results", "结果")})
                    </Button>
                  </div>
                </SheetContent>
              </Sheet>
            </div>

            {/* Filter chips row - compact for mobile */}
            {!isAIMode && <div className="flex items-center gap-1.5 overflow-x-auto pb-0.5 scrollbar-none">
              {/* Country dropdown */}
              {countries.length > 0 && (
                <Popover onOpenChange={(open) => { if (!open) setCountrySearch(""); }}>
                  <PopoverTrigger asChild>
                    <button className={`flex-shrink-0 flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium transition-all border ${
                      selectedCountry 
                        ? 'bg-primary text-primary-foreground border-primary' 
                        : 'bg-background text-foreground border-border/60 hover:border-primary/40'
                    }`}>
                      <Globe className="w-3 h-3" />
                      {selectedCountry ? getCountryDisplayName(selectedCountry) : t("restaurants.allCountries", "全部国家")}
                      {selectedCountry && (
                        <X className="w-3 h-3 ml-0.5 opacity-70 hover:opacity-100" onClick={(e) => { e.stopPropagation(); setSelectedCountry(null); setSelectedDistrict(null); }} />
                      )}
                    </button>
                  </PopoverTrigger>
                  <PopoverContent className="w-52 p-2" align="start">
                    {countries.length > 5 && (
                      <div className="pb-2">
                        <Input
                          placeholder={t("common.search", "搜索") + "..."}
                          value={countrySearch}
                          onChange={(e) => setCountrySearch(e.target.value)}
                          className="h-8 text-sm"
                          autoFocus
                        />
                      </div>
                    )}
                    <div className="space-y-0.5 max-h-[280px] overflow-y-auto">
                      {!countrySearch && (
                        <button
                          onClick={() => { setSelectedCountry(null); setSelectedDistrict(null); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            !selectedCountry ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {t("restaurants.allCountries", "全部国家")}
                        </button>
                      )}
                      {countries
                        .filter(c => !countrySearch || getCountryDisplayName(c).toLowerCase().includes(countrySearch.toLowerCase()) || c.toLowerCase().includes(countrySearch.toLowerCase()))
                        .map((country) => (
                        <button
                          key={country}
                          onClick={() => { setSelectedCountry(selectedCountry === country ? null : country); setSelectedDistrict(null); setCountrySearch(""); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            selectedCountry === country ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {getCountryDisplayName(country)}
                        </button>
                      ))}
                      {countrySearch && countries.filter(c => getCountryDisplayName(c).toLowerCase().includes(countrySearch.toLowerCase()) || c.toLowerCase().includes(countrySearch.toLowerCase())).length === 0 && (
                        <p className="px-3 py-2 text-sm text-muted-foreground">{t("common.noResults", "无结果")}</p>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              )}

              {/* District dropdown - only when country selected */}
              {selectedCountry && districts.length > 0 && (
                <Popover onOpenChange={(open) => { if (!open) setDistrictSearch(""); }}>
                  <PopoverTrigger asChild>
                    <button className={`flex-shrink-0 flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium transition-all border ${
                      selectedDistrict 
                        ? 'bg-primary/90 text-primary-foreground border-primary/90' 
                        : 'bg-background text-foreground border-border/60 hover:border-primary/40'
                    }`}>
                      <Building2 className="w-3 h-3" />
                      {selectedDistrict ? getLocalizedCityName(selectedDistrict, i18n.language) : t("restaurants.allDistricts", "全部城市")}
                      {selectedDistrict && (
                        <X className="w-3 h-3 ml-0.5 opacity-70 hover:opacity-100" onClick={(e) => { e.stopPropagation(); setSelectedDistrict(null); }} />
                      )}
                    </button>
                  </PopoverTrigger>
                  <PopoverContent className="w-52 p-2" align="start">
                    {districts.length > 5 && (
                      <div className="pb-2">
                        <Input
                          placeholder={t("common.search", "搜索") + "..."}
                          value={districtSearch}
                          onChange={(e) => setDistrictSearch(e.target.value)}
                          className="h-8 text-sm"
                          autoFocus
                        />
                      </div>
                    )}
                    <div className="space-y-0.5 max-h-[280px] overflow-y-auto">
                      {!districtSearch && (
                        <button
                          onClick={() => setSelectedDistrict(null)}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            !selectedDistrict ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {t("restaurants.allDistricts", "全部城市")}
                        </button>
                      )}
                      {districts
                        .filter(c => {
                          if (!districtSearch) return true;
                          const search = districtSearch.toLowerCase();
                          const localized = getLocalizedCityName(c, i18n.language).toLowerCase();
                          return c.toLowerCase().includes(search) || localized.includes(search);
                        })
                        .map((district) => (
                        <button
                          key={district}
                          onClick={() => { setSelectedDistrict(selectedDistrict === district ? null : district); setDistrictSearch(""); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            selectedDistrict === district ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {getLocalizedCityName(district, i18n.language)}
                        </button>
                      ))}
                      {districtSearch && districts.filter(c => { const s = districtSearch.toLowerCase(); return c.toLowerCase().includes(s) || getLocalizedCityName(c, i18n.language).toLowerCase().includes(s); }).length === 0 && (
                        <p className="px-3 py-2 text-sm text-muted-foreground">{t("common.noResults", "无结果")}</p>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              )}

              {countries.length > 0 && <div className="w-px h-4 bg-border/40 flex-shrink-0" />}

              {/* Radius chips - compact */}
              {[
                { value: null, label: t("restaurants.all", "全部") },
                { value: 5, label: "5km" },
                { value: 10, label: "10km" },
                { value: 20, label: "20km" },
                { value: 50, label: "50km" },
              ].map((option) => (
                <button
                  key={option.value ?? 'all'}
                  onClick={() => handleRadiusChange(option.value)}
                  className={`flex-shrink-0 px-2.5 py-1 rounded-full text-xs font-medium transition-all border flex items-center gap-0.5 ${
                    radiusFilter === option.value
                      ? 'bg-primary text-primary-foreground border-primary'
                      : 'bg-background text-foreground border-border/60 hover:border-primary/40'
                  }`}
                >
                  {option.value === null && <Navigation className="w-3 h-3" />}
                  {option.label}
                </button>
              ))}
            </div>}

            {/* Row: Active filter tags summary - hidden in AI mode */}
            {!isAIMode && (selectedActivity || selectedCountry || nearLandmarkName || selectedDistrict || verifiedFilter !== "all" || radiusFilter || selectedTypes.length > 0) && (
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-xs text-muted-foreground">{t("restaurants.activeFilters", "筛选中")}:</span>
                <Badge variant="outline" className="text-xs font-medium">{totalCount}</Badge>
                {nearLandmarkName && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    <Landmark className="w-3 h-3" />
                    {nearLandmarkName}
                  </Badge>
                )}
                {selectedTypes.length > 0 && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {selectedTypes.map(t => getTypeDisplayLabel(t, i18n.language)).join(', ')}
                    <button onClick={() => setSelectedTypes([])} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {verifiedFilter !== "all" && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {verifiedFilter === "verified" ? t("restaurants.verifiedOnly", "已认证") : t("restaurants.unverifiedOnly", "未认证")}
                    <button onClick={() => setVerifiedFilter("all")} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {!nearLandmarkName && selectedCountry && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {selectedCountry}{selectedDistrict ? ` · ${selectedDistrict}` : ''}
                    <button onClick={() => { setSelectedCountry(null); setSelectedDistrict(null); }} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {selectedActivity && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {(() => {
                      const a = activitiesWithRestaurants.find(a => a.id === selectedActivity);
                      if (!a) return '';
                      const lang = i18n.language;
                      return activityTranslations[a.id] || (lang === 'zh' ? (a.badge_text_zh || a.title_zh) : lang === 'pt' ? (a.badge_text_pt || a.title_pt) : (a.badge_text_en || a.title_en));
                    })()}
                    <button onClick={() => { setSelectedActivity(null); setActivityRestaurantIds([]); }} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {radiusFilter && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {radiusFilter} km
                    <button onClick={() => setRadiusFilter(null)} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
              </div>
            )}
          </div>
        </div>

        {/* AI Search Results Banner */}
        {isAIMode && !isAISearching && aiResults && (
          <div className="mb-4 flex items-center gap-2 px-1">
            <Sparkles className="h-4 w-4 text-primary flex-shrink-0" />
            <span className="text-sm text-foreground/80">{aiResults.message}</span>
            {aiResults.landmark && (
              <Badge variant="secondary" className="text-xs gap-1">
                <Landmark className="w-3 h-3" />
                {aiResults.landmark.name}
              </Badge>
            )}
            <span className="text-xs text-muted-foreground ml-auto">
              {aiResults.restaurants.length} {t("restaurants.results", "结果")}
            </span>
          </div>
        )}
        {aiError && (
          <div className="mb-4 text-sm text-destructive px-1">{aiError}</div>
        )}

        {/* Content Area */}
        {/* Loading State - Show skeleton immediately, don't wait for undefined */}
        {(isAISearching || (!isAIMode && isLoading)) ? (
          viewMode === "map" ? (
            <MapViewSkeleton />
          ) : (
            <RestaurantListSkeleton count={6} />
          )
        ) : (isAIMode ? aiResults?.restaurants.length === 0 : (viewMode === "map" ? mapFilteredRestaurants.length === 0 : totalCount === 0)) ? (
          /* Empty State */
          <div className={`text-center ${viewMode === "map" ? "flex-1 flex flex-col justify-center px-4" : "py-20"}`}>
            <p className="text-xl text-muted-foreground">{t("restaurants.noResults")}</p>
            <p className="text-muted-foreground mt-2">{t("restaurants.noResultsDesc")}</p>
          </div>
        ) : (
          /* Content */
          <>
            {/* Map View */}
            {viewMode === "map" && mapFilteredRestaurants.length > 0 && (
              <div className="relative flex-1 min-h-[300px] sm:min-h-[400px] lg:mx-4 lg:mb-4 lg:rounded-lg overflow-hidden lg:shadow-lg">
                <RestaurantMap restaurants={mapFilteredRestaurants} onRestaurantClick={handleRestaurantClick} userLocation={userLocation} radiusFilter={radiusFilter} showViewDetailsButton={true} />
                {/* Logo and text in bottom left corner of map */}
                <div className="absolute bottom-4 left-4 z-10 pointer-events-none flex items-center gap-2 bg-background/90 px-3 py-2 rounded-full shadow-lg">
                  <img 
                    src={logoIcon} 
                    alt="Xiaoxiong Market Logo" 
                    className="h-6 w-6 object-contain"
                  />
                  <span className="text-sm font-semibold text-foreground whitespace-nowrap">
                    {i18n.language === 'zh' ? '小熊市场' : 'Xiaoxiong Market'}
                  </span>
                </div>
              </div>
            )}

            {/* List View */}
            {viewMode === "list" && (isAIMode ? (aiResults?.restaurants || []) : displayedRestaurants).length > 0 && (
              <>
                <div className={`grid gap-6 ${listColumns === 1 ? 'grid-cols-1' : 'grid-cols-2'} md:grid-cols-2 lg:grid-cols-3`}>
                  {(isAIMode ? (aiResults?.restaurants || []).map(r => ({ ...localizeRestaurant(r as any), distance: (r as any).distance_km })) : displayedRestaurants).map((restaurant: any) => {
                    const isCompactMode = isMobile && listColumns === 2;
                    const isRestaurantFavorite = favoriteIds.includes(restaurant.id);

                    return (
                      <MichelinRestaurantCard
                        key={restaurant.id}
                        restaurant={restaurant}
                        isCompactMode={isCompactMode}
                        isFavorite={isRestaurantFavorite}
                        user={user}
                        onToggleFavorite={handleToggleFavorite}
                        onStoryClick={(r) => {
                          const displayName = i18n.language === 'zh' ? r.name : (i18n.language === 'pt' ? (r.name_pt || r.name_en || r.name) : (r.name_en || r.name));
                          setStoryDialog({ id: r.id, name: displayName, story: r.photo_story_zh || r.photo_story_en || r.photo_story_pt, address: r.address, image_url: r.image_url, photo_story_zh: r.photo_story_zh, photo_story_en: r.photo_story_en, photo_story_pt: r.photo_story_pt });
                        }}
                        onClaimClick={(r) => setClaimDialog({ id: r.id, name: getLocalizedField(r, "name"), address: r.address })}
                        onNavigate={(r) => {
                          setNavigationTarget({ lat: r.lat, lng: r.lng, name: getLocalizedField(r, "name") });
                          setShowNavigationDialog(true);
                        }}
                        onVerifiedClick={() => setVerifiedDialog(true)}
                        getLocalizedField={getLocalizedField}
                        getTypeDisplayLabel={getTypeDisplayLabel}
                        formatName={(r) => {
                          if (translations && translations[r.id]) {
                            const parts = translations[r.id].split('\n');
                            return formatTrademarkSymbols(parts[0] || getLocalizedField(r, "name"));
                          }
                          return formatTrademarkSymbols(getLocalizedField(r, "name"));
                        }}
                        translations={translations}
                        language={i18n.language}
                        distance={restaurant.distance}
                        realUserGps={realUserGps}
                        nearLandmarkLocation={nearLandmarkLocation}
                        t={t}
                        requireLogin={requireLogin}
                        getBuildingStorySnippet={(r: any) => getBuildingStorySnippet(r, 60, i18n.language)}
                        calculateDistance={calculateDistance}
                        userLocation={userLocation}
                      />
                    );
                  })}
                </div>
                
                {/* Load More Button - only for non-AI mode */}
                {!isAIMode && hasMore && (
                  <div className="flex justify-center mt-8">
                    <Button onClick={loadMore} size="lg" variant="outline">
                      {t("common.loadMore")} ({displayedCount} / {totalCount})
                    </Button>
                  </div>
                )}
              </>
            )}
          </>
        )}

        <NavigationConfirmDialog
          open={showNavigationDialog}
          onOpenChange={setShowNavigationDialog}
          onConfirm={() => {
            if (navigationTarget) {
              openNavigation(navigationTarget.lat, navigationTarget.lng, navigationTarget.name);
            }
            setShowNavigationDialog(false);
          }}
          destinationName={navigationTarget?.name || ""}
        />

        <LocationPermissionDialog
          open={showLocationDialog}
          onOpenChange={setShowLocationDialog}
          onConfirm={requestLocation}
        />

        <Dialog open={!!storyDialog} onOpenChange={(open) => !open && setStoryDialog(null)}>
          <DialogContent className="max-w-md max-h-[80vh] overflow-y-auto p-0 gap-0 border-none [&>button]:bg-primary/85 [&>button]:backdrop-blur-md [&>button]:text-primary-foreground [&>button]:rounded-full [&>button]:border [&>button]:border-white/20 [&>button]:shadow-[0_2px_8px_rgba(0,0,0,0.3),inset_0_1px_0_rgba(255,255,255,0.15)] [&>button]:hover:bg-primary [&>button]:hover:scale-105 [&>button]:transition-all [&>button]:duration-200 [&>button]:w-7 [&>button]:h-7 [&>button]:top-3 [&>button]:right-3 [&>button]:opacity-100 [&>button]:flex [&>button]:items-center [&>button]:justify-center [&>button>svg]:w-3.5 [&>button>svg]:h-3.5">
            {/* Hero image */}
            {storyDialog?.image_url && (
              <div className="relative w-full h-48 overflow-hidden rounded-t-lg">
                <img 
                  src={storyDialog.image_url} 
                  alt={storyDialog?.name || ''} 
                  className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />
                <div className="absolute bottom-0 left-0 right-0 px-5 pb-4">
                  <DialogHeader>
                    <DialogTitle className="text-lg text-white flex items-center gap-2 drop-shadow-lg">
                      <StoryTitleWithCounts restaurantId={storyDialog?.id} className="text-white" />
                    </DialogTitle>
                    <DialogDescription className="text-sm text-white/80 mt-0.5 drop-shadow">
                      {storyDialog?.name}
                    </DialogDescription>
                  </DialogHeader>
                </div>
              </div>
            )}
            {/* Fallback header when no image */}
            {!storyDialog?.image_url && (
              <div className="relative bg-gradient-to-br from-primary/90 via-primary-light/80 to-accent/85 px-6 pt-6 pb-5 rounded-t-lg">
                <div className="absolute inset-0 opacity-[0.06] rounded-t-lg" style={{ backgroundImage: 'url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.4\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")' }} />
                <DialogHeader className="relative z-10">
                  <DialogTitle className="text-lg text-primary-foreground flex items-center gap-2">
                    <StoryTitleWithCounts restaurantId={storyDialog?.id} />
                  </DialogTitle>
                  <DialogDescription className="text-sm text-primary-foreground/70 mt-1">
                    {storyDialog?.name}
                  </DialogDescription>
                </DialogHeader>
              </div>
            )}
            {/* Story content */}
            <StoryDialogContent restaurant={storyDialog} />
          </DialogContent>
        </Dialog>

        {/* Verified Store Dialog */}
        <Dialog open={verifiedDialog} onOpenChange={setVerifiedDialog}>
          <DialogContent className="max-w-sm">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <BadgeCheck className="w-5 h-5 text-primary fill-primary/10" />
                {t("restaurants.verifiedStore")}
              </DialogTitle>
              <DialogDescription className="text-sm leading-relaxed pt-2">
                {t("restaurants.verifiedStoreDesc")}
              </DialogDescription>
            </DialogHeader>
          </DialogContent>
        </Dialog>

        {/* Claim Restaurant Dialog */}
        <ClaimRestaurantDialog
          open={!!claimDialog}
          onOpenChange={(open) => !open && setClaimDialog(null)}
          restaurant={claimDialog}
        />
      </div>
    </div>
  );

  // Only wrap with PullToRefresh in list mode
  if (viewMode === "list") {
    return <PullToRefresh onRefresh={handleRefresh}>{pageContent}</PullToRefresh>;
  }

  return pageContent;
};

export default Restaurants;